mapper.select:
SELECT 
FROM tb_prov_facility_device t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.facility_uid = #{facilityUid}


    AND t.facility_type = #{facilityType}


    AND t.preset_state = #{presetState}

ORDER BY t.id DESC
